// FOIL admission race-speed benchmark — the speed-daemon impact of the ternary
// admission verdict over the legacy `accepted` boolean.
//
// HOT PATH: every topology entering the swerve edge must clear the FOIL gate
// before it executes. A proof can be (a) clean, (b) forged/structurally invalid,
// or (c) over-budget: structurally well-formed but its verification has not yet
// settled under the constant bound (`verificationCost > constantBound`) — latent,
// recheck-later. Case (c) is the one the boolean squashed.
//
// The boolean (`accepted`) maps every non-Accept proof to the SAME bucket. A
// latent over-budget proof reads as a hard reject, indistinguishable from a
// forgery, so the honest producer must RE-PROVE the certificate from scratch
// (the lean4-static-prover regenerates it — the expensive op) and resubmit.
//
// The trit (`verdict`: Accept / Decline / Abstain) keeps the latent proof: Abstain
// defers it for a cheap RE-CHECK (re-run the constant-time verifier when the
// budget settles), no re-prove. Proving >> verifying (the standard ZK asymmetry),
// so every avoided re-prove is the race-speed payoff measured here.
//
// Both policies classify each proof with the REAL `verifyFoilAdmissionProof`, and
// admission is exercised through the REAL `FoilEdgeRuntime`. The stream is seeded,
// so costs are exact. HONEST SCOPE: clean and forged proofs cost the same under
// both policies (a forgery has no honest producer to re-prove); the entire
// differential is the latent/over-budget fraction paying re-prove (binary) vs
// recheck (ternary). The PROVE/VERIFY ratio is a parameter and is swept.

import {
  createStaticFoilAdmissionProof,
  verifyFoilAdmissionProof,
  FoilEdgeRuntime,
  FoilAdmissionRejectedError,
  Verdict,
  isAccept,
  isDefer,
  isReject,
  ZERO_DEFICIT_FOIL_CERTIFICATE,
  type FoilAdmissionProof,
} from '../foil-edge-gate';

// ---- deterministic PRNG (mulberry32) -------------------------------------
function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ---- the three proof classes (verified against the real gate below) -------
const CLEAN: FoilAdmissionProof = createStaticFoilAdmissionProof(
  ZERO_DEFICIT_FOIL_CERTIFICATE,
  { verificationCost: 1, constantBound: 4 },
);
// Over-budget: every field clean, cost exceeds the bound -> Abstain (latent).
const OVER_BUDGET: FoilAdmissionProof = createStaticFoilAdmissionProof(
  ZERO_DEFICIT_FOIL_CERTIFICATE,
  { verificationCost: 9, constantBound: 4 },
);
// Forged: nonzero classical deficit -> Decline (hard, fail-closed).
const FORGED: FoilAdmissionProof = createStaticFoilAdmissionProof(
  { classicalDeficit: 3, entropyEliminated: true, voidBound: 0, edgeCount: 0 },
  { verificationCost: 1, constantBound: 4 },
);

// Validate that the REAL gate returns the verdicts this benchmark assumes.
if (!isAccept(verifyFoilAdmissionProof(CLEAN).verdict!)) {
  throw new Error('FOIL bench: expected CLEAN -> Accept');
}
if (!isDefer(verifyFoilAdmissionProof(OVER_BUDGET).verdict!)) {
  throw new Error('FOIL bench: expected OVER_BUDGET -> Abstain (defer)');
}
if (!isReject(verifyFoilAdmissionProof(FORGED).verdict!)) {
  throw new Error('FOIL bench: expected FORGED -> Decline');
}

// Sanity: FoilEdgeRuntime actually admits clean and throws (closed) on latent,
// with the deferred case carrying the Abstain verdict on its error.
{
  const rt = new FoilEdgeRuntime();
  if (!rt.admit({ ggGraph: new Uint8Array(1), zkProof: CLEAN }).accepted) {
    throw new Error('FOIL bench: runtime should admit CLEAN');
  }
  let deferredVerdict: Verdict | undefined;
  try {
    rt.admit({ ggGraph: new Uint8Array(1), zkProof: OVER_BUDGET });
  } catch (e) {
    if (e instanceof FoilAdmissionRejectedError) deferredVerdict = e.verdict;
  }
  if (deferredVerdict !== Verdict.Abstain) {
    throw new Error('FOIL bench: latent admit should fail-closed with Abstain');
  }
}

// ---- cost model ----------------------------------------------------------
const VERIFY = 1; // constant-time gate verify (the ZK verifier side).

// Per-proof cost under each policy. The only divergence is the latent class.
function costTernary(verdict: Verdict): number {
  if (isAccept(verdict)) return VERIFY; // admit
  if (isReject(verdict)) return VERIFY; // forged -> drop
  return VERIFY + VERIFY; // Abstain -> initial + one cheap recheck later
}
function costBinary(verdict: Verdict, proveCost: number): number {
  if (isAccept(verdict)) return VERIFY; // admit
  if (isReject(verdict)) return VERIFY; // forged -> drop (no honest re-prove)
  // Latent reads as hard reject (bool can't tell it from a forgery): the honest
  // producer re-proves from scratch and resubmits.
  return VERIFY + proveCost + VERIFY;
}

interface Row {
  latentFrac: number;
  proveCost: number;
  tCost: number;
  bCost: number;
}

function runStream(
  rng: () => number,
  count: number,
  latentFrac: number,
  forgedFrac: number,
  proveCost: number,
): { tCost: number; bCost: number } {
  let tCost = 0;
  let bCost = 0;
  for (let i = 0; i < count; i++) {
    const r = rng();
    const proof =
      r < latentFrac
        ? OVER_BUDGET
        : r < latentFrac + forgedFrac
          ? FORGED
          : CLEAN;
    const verdict = verifyFoilAdmissionProof(proof).verdict!;
    tCost += costTernary(verdict);
    bCost += costBinary(verdict, proveCost);
  }
  return { tCost, bCost };
}

const COUNT = 2000;
const FORGED_FRAC = 0.05; // fixed background forgery rate
const latentFracs = [0.0, 0.05, 0.1, 0.2];
const proveCosts = [50, 100, 200]; // prove >> verify (=1); swept

const rows: Row[] = [];
for (const proveCost of proveCosts) {
  for (const latentFrac of latentFracs) {
    const rng = mulberry32(0xc0ffee ^ (proveCost << 4) ^ (latentFrac * 1000));
    const { tCost, bCost } = runStream(
      rng,
      COUNT,
      latentFrac,
      FORGED_FRAC,
      proveCost,
    );
    rows.push({ latentFrac, proveCost, tCost, bCost });
  }
}

// ---- report --------------------------------------------------------------
const f = (x: number) => x.toFixed(0).padStart(9);
 
console.log(
  '\nFOIL admission race-speed (' +
    COUNT +
    ' proofs/stream, forged=' +
    FORGED_FRAC +
    ', VERIFY=1)\n' +
    ' prove  latent | total cost tern/bin    | speedup (bin/tern)',
);
for (const r of rows) {
  const x = r.bCost / r.tCost;
   
  console.log(
    `  ${String(r.proveCost).padStart(4)}  ${r.latentFrac.toFixed(2)}   |` +
      `${f(r.tCost)}/${f(r.bCost)}     |  ${x.toFixed(2)}x`,
  );
}

// ---- invariants (deterministic) ------------------------------------------
for (const r of rows) {
  if (r.tCost > r.bCost) {
    throw new Error('FOIL bench: ternary cost must never exceed binary');
  }
  if (r.latentFrac === 0 && r.tCost !== r.bCost) {
    throw new Error('FOIL bench: with no latent proofs the policies must tie');
  }
  if (r.latentFrac > 0 && r.bCost <= r.tCost) {
    throw new Error('FOIL bench: latent proofs must make binary strictly costlier');
  }
}
// At the stressed corner (20% latent, prove=200) binary must cost far more.
const corner = rows.find((r) => r.latentFrac === 0.2 && r.proveCost === 200)!;
if (corner.bCost < corner.tCost * 3) {
  throw new Error('FOIL bench: expected >=3x at the stressed corner');
}

 
console.log('\nFOIL race-speed bench: all invariants held.');
